	std::cout << rotl(bits1) << '\n';

	std::bitset<4> bits2{ 0b1001 };
	std::cout << rotl(bits2) << '\n';

	return 0;
}Next lessonO.3Bit manipulation with bitwise operators and bit masksBack to table of contentsPrevious lessonO.1Bit flags and bit manipulation via std::bitset

